interface User {
  name: string;
  age: number;
}

// Now we can use uppercase `User` as a type!
let player1: User = { name: "Bob", age: 25 };
let player2: User = { name: "Alice", age: 30 };

// We strictly expect a complete User object
function printAge(u: User) {
  console.log(u.name + " is " + u.age);
}
